    let mut prefix_mod = vec![0; nums.len() + 1];
    let mut mod_counts = std::collections::HashMap::new();
    mod_counts.insert(0, 1);
    let mut total_sum = 0;

    for i in 0..nums.len() {
        total_sum += nums[i];
        prefix_mod[i + 1] = (prefix_mod[i] + nums[i]) % k;
        *mod_counts.entry(prefix_mod[i + 1]).or_insert(0) += 1;
