fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut prefix_sum = 0;
    let mut mod_counts = std::collections::HashMap::new();
    mod_counts.insert(0, 1);
    let mut min_sum = i64::MAX;

    for &num in &nums {
        prefix_sum = (prefix_sum + num) % k;
        if let Some(count) = mod_counts.get(&prefix_sum) {
            min_sum = std::cmp::min(min_sum, (prefix_sum as i64) * count as i64);
        }
        mod_counts.insert(prefix_sum, mod_counts.get(&prefix_sum).copied().unwrap_or(0) + 1);
    }

    min_sum
}
